export default {
    head() {
        return {
        title: this.$store.getters.headTitle,
        link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
        };
    },
    layout: "user_lauout",
    async asyncData({$get, query}) {
        const data = {
            id: query.afterSaleId
        };
        let lists = {}
        let res = await $get("after_sale/detail", {params: data});
        if(res.code == 1) {
            lists = res.data;
        }
        return {
            lists,
        }
    },
    data() {
        return {

        }
    },
    methods: {

    }
}
